    g = [[] for _ in range(h * w)]
    for i in range(h):
        for j in range(w):
            idx = i * h + j
            if i - 1 >= 0:
                g[idx].append(idx - h)
            if i + 1 < h:
                g[idx].append(idx + h)
            if j - 1 >= 0:
                g[idx].append(idx - 1)
            if j + 1 < w:
                g[idx].append(idx + 1)
    a = torch.zeros(h * w, h * w)
    d_isqrt = torch.zeros(h * w, h * w)
    for i, node in enumerate(g):
